  websiteUrl: data.directory_website_url || data.raw_response?.website_url || null,
  profileUrl: data.profile_url || null,
  verificationStatus: data.verification_status || 'not_checked',
  verificationMessage: data.verification_message || null,
  nextVerificationAt: data.next_verification_at || null,
  manualInstructions: data.raw_response?.manual_instructions || null,
  copyPayload: data.raw_response?.copy_payload || null,
  updatedAt: now,
};

const row = {
  sync_id: syncId,
  profile_id: data.profile_id || data.location_id || data.company_id || data.id,
  channel: channelCode,
  status: data.status || 'error',
  status_code: data.status_code || data.statusCode || 400,
  message: data.message || `Processed ${channelCode}`,
  duration_ms: resultForFrontend.durationMs,
  created_at: data.created_at || now,

  // Campos para directory_submissions
  company_id: data.company_id,
  location_id: data.location_id,
  user_id: data.user_id,
  channel_code: channelCode,
  submission_type: resultForFrontend.submissionType,
  directory_name: resultForFrontend.directoryName,
  form_url: resultForFrontend.formUrl,
  profile_url: resultForFrontend.profileUrl,
  verification_status: resultForFrontend.verificationStatus,
  verification_message: resultForFrontend.verificationMessage,
  next_verification_at: resultForFrontend.nextVerificationAt,
  submitted_at: ['sent', 'submitted', 'manual_required'].includes(resultForFrontend.status) ? now : null,
  raw_response: {
    ...(data.raw_response || {}),
    ...resultForFrontend,
  }
};

try {
  const staticData = $getWorkflowStaticData('global');
  staticData.p2SyncResults = staticData.p2SyncResults || {};
  staticData.p2SyncResults[syncId] = staticData.p2SyncResults[syncId] || {
    started_at: now,
    expected_channels: [],
    ignored_provider_channels: [],
    results: {}
  };
  staticData.p2SyncResults[syncId].results[channelCode] = resultForFrontend;
} catch (e) {
  row.static_data_warning = e.message;
}

return [{ json: row }];

// Resposta final completa para o frontend usando sync_logs como fonte da verdade.
// Por que: em n8n 2.4.8 o Split In Batches/Loop pode entregar apenas o último item ao Respond to Webhook.
// Então, após o loop, buscamos todos os canais gravados em sync_logs pelo mesmo sync_id.

const supabaseUrl = 'https://fljcywbqzzakwgzyguvl.supabase.co';
// Cole sua service_role key do Supabase abaixo, sem "Bearer".
const serviceKey = 'COLE_AQUI_SUA_SUPABASE_SERVICE_ROLE_KEY';

const incoming = $input.first()?.json || {};
let original = {};
try {
  original = $('Function - Validate Input').first().json || {};
} catch (e) {
  original = {};
}

const syncId = incoming.sync_id || original.sync_id;
if (!syncId) {
  throw new Error('Não foi possível identificar sync_id para montar a resposta final.');
}

const expectedChannels = Array.isArray(original.channels)
  ? original.channels.map(c => String(c).toLowerCase())
  : [];

const ignoredProviderChannels = Array.isArray(original.ignored_provider_channels)
  ? original.ignored_provider_channels
  : [];

const httpRequest = this.helpers.httpRequest.bind(this);

async function fetchRows(table) {
  const url = `${supabaseUrl}/rest/v1/${table}?sync_id=eq.${encodeURIComponent(syncId)}&select=*&order=created_at.asc`;
  return await httpRequest({
    method: 'GET',
    url,
    headers: {
      apikey: serviceKey,
      Authorization: `Bearer ${serviceKey}`,
      'Content-Type': 'application/json'
    },
    json: true,
  });
}

let rows = [];
let source = 'sync_logs';
let fetchError = null;

try {
  rows = await fetchRows('sync_logs');
} catch (e) {
  fetchError = e.message;
  rows = [];
}

// Fallback: se não achar sync_logs, tenta montar com itens do nó Function - Prepare Sync Logs.
if (!Array.isArray(rows) || rows.length === 0) {
  source = 'prepare_sync_logs_fallback';
  try {
    rows = $items('Function - Prepare Sync Logs').map(item => item.json || {});
  } catch (e) {
    rows = [];
  }
}

const results = {};

for (const row of rows) {
  const channel = String(row.channel || row.channel_code || row.current_channel || '').toLowerCase().trim();
  if (!channel) continue;

  let raw = row.raw_response || {};
  if (typeof raw === 'string') {
    try { raw = JSON.parse(raw); } catch (e) { raw = {}; }
  }

  results[channel] = {
    status: row.status || raw.status || 'error',
    statusCode: row.status_code || row.statusCode || raw.statusCode || 400,
    message: row.message || raw.message || `Processed ${channel}`,
    durationMs: row.duration_ms || row.durationMs || raw.durationMs || null,
    submissionType: row.submission_type || raw.submissionType || raw.submission_type || null,
    directoryName: row.directory_name || raw.directoryName || raw.directory_name || channel,
    formUrl: row.form_url || raw.formUrl || raw.form_url || null,
    websiteUrl: raw.websiteUrl || raw.website_url || null,
    profileUrl: row.profile_url || raw.profileUrl || raw.profile_url || null,
    verificationStatus: row.verification_status || raw.verificationStatus || raw.verification_status || 'not_checked',
    verificationMessage: row.verification_message || raw.verificationMessage || raw.verification_message || null,
    nextVerificationAt: row.next_verification_at || raw.nextVerificationAt || raw.next_verification_at || null,
    manualInstructions: raw.manualInstructions || raw.manual_instructions || null,
    copyPayload: raw.copyPayload || raw.copy_payload || null,
    createdAt: row.created_at || null,
    updatedAt: row.updated_at || row.created_at || null
  };
}

// Se temos a lista original de canais, garante que tudo selecionado apareça no retorno.
// Isso ajuda o frontend a mostrar erro/pendência quando algum canal não fechou corretamente.
for (const channel of expectedChannels) {
  if (!results[channel]) {
    results[channel] = {
      status: 'not_returned',
      statusCode: 202,
      message: `Canal ${channel} foi selecionado, mas não retornou resultado final no n8n. Verifique sync_logs/directory_submissions no Supabase.`,
      durationMs: null,
      createdAt: null,
      updatedAt: null
    };
  }
}

const resultValues = Object.values(results);
const successStatuses = ['success', 'sent', 'submitted', 'found_online', 'ok'];
const manualStatuses = ['manual_required', 'manual', 'inactive', 'not_implemented', 'pending_review', 'manual_check_required', 'captcha_required'];
const errorStatuses = ['error', 'failed', 'not_returned', 'not_found', 'data_mismatch'];

const successCount = resultValues.filter(item => successStatuses.includes(item.status)).length;
const manualCount = resultValues.filter(item => manualStatuses.includes(item.status)).length;
const errorCount = resultValues.filter(item => errorStatuses.includes(item.status)).length;
const totalChannels = Math.max(expectedChannels.length, resultValues.length);

const success = resultValues.length > 0 && errorCount === 0 && (successCount + manualCount) === resultValues.length;

return [
  {
    json: {
      success,
      sync_id: syncId,
      timestamp: new Date().toISOString(),
      total_channels: totalChannels,
      success_count: successCount,
      manual_count: manualCount,
      error_count: errorCount,
      ignored_provider_channels: ignoredProviderChannels,
      response_source: source,
      fetch_error: fetchError,
      results
    }
  }
];
